import React from 'react';
import { Badge, type BadgeProps } from '@linm-soft-org/linm-web-common-components';
import {
  type CustomerTypeCode,
  getCustomerTypeLabel,
} from '../../constants/partnerFieldLabels';
import styles from './CustomerTypeBadge.module.css';

export interface CustomerTypeBadgeProps {
  customerType?: string | null;
  className?: string;
  'data-testid'?: string;
}

const TYPE_STYLE: Record<CustomerTypeCode, string> = {
  Customer: styles.typeCustomer,
  Supplier: styles.typeSupplier,
  Both: styles.typeBoth,
};

const BADGE_VARIANT: Record<CustomerTypeCode, BadgeProps['variant']> = {
  Customer: 'info',
  Supplier: 'secondary',
  Both: 'success',
};

function resolveCustomerTypeCode(customerType?: string | null): CustomerTypeCode | undefined {
  const key = customerType?.trim();
  if (key === 'Customer' || key === 'Supplier' || key === 'Both') return key;
  return undefined;
}

/** Pill loại ĐT — KH (xanh) · NCC (tím) · Both (xanh lá). */
export const CustomerTypeBadge: React.FC<CustomerTypeBadgeProps> = ({
  customerType,
  className,
  'data-testid': testId,
}) => {
  const label = getCustomerTypeLabel(customerType);
  const typeCode = resolveCustomerTypeCode(customerType);
  if (!label || !typeCode) return null;

  return (
    <span className={styles.wrap} data-testid={testId}>
      <Badge
        variant={BADGE_VARIANT[typeCode]}
        size="sm"
        rounded
        className={[styles.badge, TYPE_STYLE[typeCode], className].filter(Boolean).join(' ')}
      >
        {label}
      </Badge>
    </span>
  );
};
